import NextAuth, { type NextAuthOptions } from "next-auth";

export const runtime = "nodejs";

const authOptions: NextAuthOptions = {
  debug: true,
  secret: process.env.NEXTAUTH_SECRET,
  session: { strategy: "jwt" },
  providers: [
    {
      id: "roblox",
      name: "Roblox",
      type: "oauth",

      // Important: define issuer metadata so "iss" validation passes
      issuer: "https://apis.roblox.com/oauth/",
      wellKnown: "https://apis.roblox.com/oauth/.well-known/openid-configuration",

      authorization: {
        url: "https://apis.roblox.com/oauth/v1/authorize",
        params: {
          scope: "openid profile",
          response_type: "code",
        },
      },
      token: "https://apis.roblox.com/oauth/v1/token",
      userinfo: "https://apis.roblox.com/oauth/v1/userinfo",
      checks: ["pkce", "state"],

      clientId: process.env.ROBLOX_CLIENT_ID,
      clientSecret: process.env.ROBLOX_CLIENT_SECRET,

      client: {
        token_endpoint_auth_method: "client_secret_post",
        id_token_signed_response_alg: "ES256",
      },

      profile(profile: any) {
        const id = profile?.sub?.toString();
        if (!id) throw new Error("Roblox profile missing sub");
        return {
          id,
          name: profile?.preferred_username ?? profile?.name ?? "Roblox User",
        };
      },
    },
  ],
  callbacks: {
    async jwt({ token, profile, account }) {
      if (account?.provider === "roblox" && profile) {
        token.sub = (profile as any).sub ?? token.sub;
        (token as any).username =
          (profile as any).preferred_username ??
          (profile as any).name ??
          (token as any).username;
      }
      return token;
    },
    async session({ session, token }) {
      if (session.user) {
        (session.user as any).id = token.sub;
        session.user.name =
          (token as any).username ?? session.user.name ?? "Roblox User";
      }
      return session;
    },
    async redirect({ baseUrl }) {
      return `${baseUrl}/dashboard`;
    },
  },
};

const handler = NextAuth(authOptions);
export { handler as GET, handler as POST };